  assert(snek_array_set(obj, 1, outside));

  // Outside of bound
  assert_false(snek_array_set(obj, 100, outside));

  // Free memory
  free(outside->data.v_string);
  free(outside);
  free(obj->data.v_array.elements);
  free(obj);
  assert(boot_all_freed());
});

